import anthropic

client = anthropic.Anthropic()

VERIFY_PROMPT = """Review the following answer to this question.
Question: {question}
Answer: {answer}

List any errors, missing information, or unclear parts.
If the answer is completely correct and complete, reply with exactly: VERIFIED
Otherwise, list specific issues to fix.
"""

REVISE_PROMPT = """You previously gave this answer:
{answer}

A review found these issues:
{issues}

Rewrite the answer to fix these specific issues while keeping the correct parts unchanged.
"""

def self_verify(question: str, max_rounds: int = 2) -> str:
    def call(messages):
        return client.messages.create(
            model="claude-sonnet-4-6",
            max_tokens=2048,
            messages=messages,
        ).content[0].text

    # Step 1: Initial generation
    answer = call([{"role": "user", "content": question}])

    for round_num in range(max_rounds):
        # Step 2: Self-verify
        verdict = call([{
            "role": "user",
            "content": VERIFY_PROMPT.format(question=question, answer=answer),
        }])

        if verdict.strip().upper().startswith("VERIFIED"):
            break  # No errors found

        # Step 3: Revise
        answer = call([{
            "role": "user",
            "content": REVISE_PROMPT.format(answer=answer, issues=verdict),
        }])

    return answer

result = self_verify(
    "Explain why Python's GIL prevents true parallelism for CPU-bound tasks "    "but not for I/O-bound tasks.",
    max_rounds=2,
)
print(result)

from dataclasses import dataclass

@dataclass
class VerificationCriteria:
    name: str
    check: str          # description of what to check
    weight: float = 1.0 # relative importance

CODE_REVIEW_CRITERIA = [
    VerificationCriteria("Correctness",   "Does the code correctly implement the requested logic?"),
    VerificationCriteria("Edge cases",    "Are edge cases (empty input, None, overflow) handled?"),
    VerificationCriteria("Readability",   "Is the code clear and well-structured?"),
    VerificationCriteria("Completeness",  "Is any required part missing?"),
]

CRITERIA_VERIFY_PROMPT = """Review this response against specific criteria.
Question: {question}
Response: {response}

For each criterion below, give: PASS / FAIL and a one-sentence reason.
{criteria_list}

After reviewing all criteria, give an overall verdict:
OVERALL: PASS (no fixes needed) or OVERALL: FAIL - <list of criteria that failed>
"""

def criteria_verify(question: str, answer: str,
                    criteria: list[VerificationCriteria]) -> dict:
    criteria_list = "\n".join(
        f"{i+1}. {c.name}: {c.check}"
        for i, c in enumerate(criteria)
    )
    report = client.messages.create(
        model="claude-sonnet-4-6",
        max_tokens=1024,
        messages=[{"role": "user", "content": CRITERIA_VERIFY_PROMPT.format(
            question=question, response=answer, criteria_list=criteria_list
        )}],
    ).content[0].text

    passed = "OVERALL: PASS" in report.upper()
    return {"passed": passed, "report": report}

import json, re
from dataclasses import dataclass

STRUCTURED_VERIFY_PROMPT = """Verify the following response and output a JSON report.
Question: {question}
Response: {response}

Return ONLY a JSON object (no markdown):
{{
  "overall": "PASS" or "FAIL",
  "issues": [
    {{"type": "factual_error" | "logic_gap" | "missing_info" | "ambiguity",
      "description": "...",
      "severity": "critical" | "minor"}}
  ],
  "confidence": <0.0-1.0>
}}
"""

@dataclass
class VerificationReport:
    overall: str
    issues: list[dict]
    confidence: float

def structured_self_verify(question: str, max_rounds: int = 2) -> tuple[str, VerificationReport]:
    answer = client.messages.create(
        model="claude-sonnet-4-6",
        max_tokens=2048,
        messages=[{"role": "user", "content": question}],
    ).content[0].text

    for _ in range(max_rounds):
        raw = client.messages.create(
            model="claude-sonnet-4-6",
            max_tokens=1024,
            messages=[{"role": "user", "content": STRUCTURED_VERIFY_PROMPT.format(
                question=question, response=answer,
            )}],
        ).content[0].text

        # Parse report
        try:
            raw_clean = re.sub(r'^```[a-z]*\n|```$', '', raw.strip(), flags=re.M).strip()
            data = json.loads(raw_clean)
            report = VerificationReport(
                overall=data.get("overall", "UNKNOWN"),
                issues=data.get("issues", []),
                confidence=float(data.get("confidence", 0.5)),
            )
        except (json.JSONDecodeError, KeyError):
            break  # Can't parse report — stop and return current answer

        if report.overall == "PASS":
            return answer, report

        # Fix critical issues only (minor issues don't warrant a revision)
        critical = [i for i in report.issues if i.get("severity") == "critical"]
        if not critical:
            return answer, report

        fix_list = "\n".join(f"- {i['description']}" for i in critical)
        answer = client.messages.create(
            model="claude-sonnet-4-6",
            max_tokens=2048,
            messages=[{"role": "user", "content":
                f"Fix these critical issues in your previous answer:\n{fix_list}\n\nPrevious answer:\n{answer}"}],
        ).content[0].text

    return answer, report

final_answer, report = structured_self_verify(
    "What is the difference between TCP and UDP? When should you use each?"
)
print(f"Verified: {report.overall}, Confidence: {report.confidence:.0%}")
if report.issues:
    for issue in report.issues:
        print(f"  [{issue['severity']}] {issue['type']}: {issue['description']}")
